import os, time, json
warnings = []
for doc in ['docs/context.md', 'docs/architecture.md']:
    if os.path.isfile(doc):
        age_days = (time.time() - os.path.getmtime(doc)) / 86400
        if age_days > 3:
            warnings.append(f'{doc} is {int(age_days)} days old')
if warnings:
    msg = 'STALE DOCS WARNING: ' + '; '.join(warnings) + '. Run /update-context to refresh.'
    print(json.dumps({'message': msg}))
" 2>/dev/null; exit 0

python3 -c "
import subprocess, os, signal
cwd = os.getcwd()
for proc_name in ['uvicorn', 'celery', 'streamlit', 'gradio']:
    try:
        result = subprocess.run(['pgrep', '-af', proc_name], capture_output=True, text=True)
        for line in result.stdout.strip().split('\n'):
            if not line:
                continue
            parts = line.split(None, 1)
            pid = parts[0]
            cmdline = parts[1] if len(parts) > 1 else ''
            if cwd in cmdline:
                os.kill(int(pid), signal.SIGTERM)
    except: pass
" 2>/dev/null; exit 0
